module RefModule (  
    input wire clk,  
    input wire reset,  
    input wire start,  
    input wire connect,  
    output reg [1:0] state  
);  
    // State encoding  
    parameter IDLE = 2'b00, SCAN = 2'b01, CONNECT = 2'b10;  
    reg [1:0] ctrl_bus_wire;  

    // Sequential logic for state transition  
    always @(posedge clk or posedge reset) begin  
        if (reset)  
            state <= IDLE;  
        else  
            state <= ctrl_bus_wire;  
    end  

    // Combinational logic for next state  
    always @(*) begin  
        case (state)  
            IDLE: begin  
                if (start)  
                    ctrl_bus_wire = SCAN;  
                else  
                    ctrl_bus_wire = IDLE;  
            end  
            SCAN: begin  
                if (connect)  
                    ctrl_bus_wire = CONNECT;  
                else  
                    ctrl_bus_wire = SCAN;  
            end  
            CONNECT: begin  
                ctrl_bus_wire = IDLE;  
            end  
            default: ctrl_bus_wire = IDLE;  
        endcase  
    end  
endmodule
